namespace sv_7848241abe7e478382a43de6101cf579.Services;

public sealed class Recipe
{
    public int Id { get; init; }
    public string Title { get; init; } = string.Empty;
    public string Description { get; init; } = string.Empty;
    public int PrepTimeMinutes { get; init; }
}

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Spaghetti Carbonara", Description = "Classic Roman pasta with eggs, cheese, pancetta, and pepper.", PrepTimeMinutes = 30 },
            new() { Id = 2, Title = "Margherita Pizza", Description = "Simple pizza with tomato sauce, mozzarella, and fresh basil.", PrepTimeMinutes = 45 },
            new() { Id = 3, Title = "Tiramisu", Description = "Layered coffee-flavored dessert with mascarpone cream.", PrepTimeMinutes = 40 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Chicken Tikka Masala", Description = "Tender chicken in a creamy spiced tomato sauce.", PrepTimeMinutes = 50 },
            new() { Id = 5, Title = "Palak Paneer", Description = "Fresh paneer cubes in a smooth spinach gravy.", PrepTimeMinutes = 35 },
            new() { Id = 6, Title = "Biryani", Description = "Fragrant layered rice dish with spices and marinated meat.", PrepTimeMinutes = 90 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Sushi Rolls", Description = "Vinegared rice with fresh fish and vegetables wrapped in nori.", PrepTimeMinutes = 60 },
            new() { Id = 8, Title = "Ramen", Description = "Rich broth with wheat noodles, pork, egg, and toppings.", PrepTimeMinutes = 120 },
            new() { Id = 9, Title = "Tempura", Description = "Lightly battered and deep-fried seafood and vegetables.", PrepTimeMinutes = 25 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_7848241abe7e478382a43de6101cf579.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null && _isLoading)
{
    <p><em>Loading recipes...</em></p>
}
else if (_recipes is not null)
{
    @if (_isLoading)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isLoading;
    private string? _error;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();
            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Only reload data when the cuisine changes, not when sort changes.
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isLoading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);
            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was superseded by a newer one; do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

